import { ccc, mol } from "@ckb-ccc/core";
export const SporeData = mol.table({
    contentType: mol.String,
    content: mol.Bytes,
    clusterId: mol.BytesOpt,
});
export function packRawSporeData(packable) {
    return ccc.bytesFrom(SporeData.encode({
        contentType: packable.contentType,
        content: packable.content,
        clusterId: packable.clusterId,
    }));
}
export function unpackToRawSporeData(unpackable) {
    return SporeData.decode(unpackable);
}
